namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough\nMozzarella cheese\nFresh basil\nSan Marzano tomatoes\nOlive oil\nSalt", Steps = "1. Preheat oven to 475°F\n2. Roll out dough on floured surface\n3. Spread crushed tomatoes evenly\n4. Add torn mozzarella pieces\n5. Bake for 10-12 minutes\n6. Top with fresh basil and drizzle olive oil", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper", Steps = "1. Cook pasta in salted water\n2. Fry guanciale until crispy\n3. Whisk eggs with grated pecorino and pepper\n4. Toss hot pasta with guanciale\n5. Remove from heat, stir in egg mixture\n6. Serve immediately with extra pecorino", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs\nYogurt\nGaram masala\nTurmeric\nTomato sauce\nHeavy cream\nGarlic\nGinger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours\n2. Grill or broil chicken until charred\n3. Sauté garlic and ginger in oil\n4. Add tomato sauce and spices, simmer\n5. Add cream and cooked chicken\n6. Simmer 10 minutes, serve with rice", AverageRating = 4.7, RatingCount = 15 },
        new Recipe { Id = 4, Title = "Vegetable Pad Thai", Category = "Thai", Ingredients = "Rice noodles\nTofu\nBean sprouts\nPeanuts\nLime\nFish sauce\nTamarind paste\nEggs", Steps = "1. Soak rice noodles in warm water\n2. Press and cube tofu, fry until golden\n3. Scramble eggs in wok\n4. Add noodles and sauce (tamarind, fish sauce, sugar)\n5. Toss with bean sprouts and tofu\n6. Serve with crushed peanuts and lime", AverageRating = 4.3, RatingCount = 8 },
        new Recipe { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomatoes\nCheddar cheese\nSour cream\nSalsa", Steps = "1. Brown ground beef in skillet\n2. Add taco seasoning and water, simmer\n3. Warm tortillas in dry pan\n4. Assemble tacos with beef and toppings\n5. Serve with salsa and sour cream", AverageRating = 4.2, RatingCount = 10 },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt", Steps = "1. Halve and pit avocados\n2. Mash avocado to desired consistency\n3. Dice onion, tomato, jalapeño, and cilantro\n4. Mix everything together\n5. Add lime juice and salt to taste\n6. Serve immediately with chips", AverageRating = 4.6, RatingCount = 18 },
        new Recipe { Id = 7, Title = "Miso Ramen", Category = "Japanese", Ingredients = "Ramen noodles\nMiso paste\nPork belly\nSoft-boiled eggs\nGreen onions\nNori\nChicken broth\nSoy sauce", Steps = "1. Simmer broth with miso paste\n2. Slice and sear pork belly\n3. Cook ramen noodles per package\n4. Prepare soft-boiled eggs (6.5 minutes)\n5. Assemble bowls: noodles, broth, toppings\n6. Garnish with nori and green onions", AverageRating = 4.9, RatingCount = 22 },
        new Recipe { Id = 8, Title = "Chocolate Chip Cookies", Category = "Desserts", Ingredients = "Butter\nSugar\nBrown sugar\nEggs\nVanilla\nFlour\nBaking soda\nChocolate chips\nSalt", Steps = "1. Cream butter and sugars until fluffy\n2. Beat in eggs and vanilla\n3. Mix flour, baking soda, and salt\n4. Combine wet and dry ingredients\n5. Fold in chocolate chips\n6. Bake at 375°F for 9-11 minutes", AverageRating = 4.4, RatingCount = 25 },
    };

    private readonly List<RecipeCategory> _categories = new()
    {
        new RecipeCategory { Name = "Italian", Description = "Classic pasta, pizza, and Mediterranean flavors", Icon = "🍝" },
        new RecipeCategory { Name = "Indian", Description = "Rich curries, aromatic spices, and vibrant dishes", Icon = "🍛" },
        new RecipeCategory { Name = "Thai", Description = "Bold flavors balancing sweet, sour, salty, and spicy", Icon = "🥘" },
        new RecipeCategory { Name = "Mexican", Description = "Vibrant tacos, salsas, and traditional favorites", Icon = "🌮" },
        new RecipeCategory { Name = "Japanese", Description = "Elegant ramen, sushi, and umami-rich dishes", Icon = "🍜" },
        new RecipeCategory { Name = "Desserts", Description = "Sweet treats, cakes, and baked goods", Icon = "🍪" },
    };

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}
"}

