@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="my-3 p-3 border rounded">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                title="Rate @star stars">
            @(star <= displayRating ? "★" : "☆")
        </button>
    }
    <span class="ms-3 text-muted">
        @CurrentRating / 5 (@RatingCount ratings)
    </span>
    @if (submitted)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public double CurrentRating { get; set; }

    [Parameter]
    public int RatingCount { get; set; }

    private int displayRating;
    private bool submitted;

    protected override void OnParametersSet()
    {
        displayRating = (int)Math.Round(CurrentRating);
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
            displayRating = stars;
        }
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit Recipe - RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

<div class="row">
    <div class="col-md-8">
        <EditForm Model="newRecipe" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
            <DataAnnotationsValidator />

            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" @bind-Value="newRecipe.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                <ValidationMessage For="() => newRecipe.Title" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" @bind-Value="newRecipe.Category" class="form-select">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in RecipeService.GetCategories())
                    {
                        <option value="@cat.Name">@cat.Name</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => newRecipe.Category" />
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients</label>
                <InputTextArea id="ingredients" @bind-Value="newRecipe.Ingredients" class="form-control" rows="6"
                    placeholder="One ingredient per line" />
                <ValidationMessage For="() => newRecipe.Ingredients" />
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps</label>
                <InputTextArea id="steps" @bind-Value="newRecipe.Steps" class="form-control" rows="8"
                    placeholder="Describe each step" />
                <ValidationMessage For="() => newRecipe.Steps" />
            </div>

            <button type="submit" class="btn btn-success">Submit Recipe</button>
        </EditForm>

        @if (showSuccess)
        {
            <div class="alert alert-success mt-3">
                ✅ Recipe submitted successfully! <a href="/recipe/@submittedId">View your recipe</a>
            </div>
        }
    </div>
</div>

@code {
    private Recipe newRecipe = new();
    private bool showSuccess;
    private int submittedId;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(newRecipe);
        submittedId = newRecipe.Id;
        showSuccess = true;
        newRecipe = new();
    }
}

