<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category yet.</p>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in recipes)
        {
            <div class="col">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

