@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="my-3 p-3 border rounded">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                title="Rate @star stars">
            @(star <= displayRating ? "★" : "☆")
        </button>
    }
    <span class="ms-3 text-muted">
        @CurrentRating / 5 (@RatingCount ratings)
    </span>
    @if (submitted)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public double CurrentRating { get; set; }

    [Parameter]
    public int RatingCount { get; set; }

    private int displayRating;
    private bool submitted;

    protected override void OnParametersSet()
    {
        displayRating = (int)Math.Round(CurrentRating);
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
            displayRating = stars;
        }
        submitted = true;
    }
}

