@page "/recipe/{RecipeId:int}"
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        }
    </ol>
</nav>

@if (recipe is null)
{
    <h1>Recipe not found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">🥗 Ingredients</h5></div>
                <div class="card-body">
                    <ul class="list-unstyled mb-0">
                        @foreach (var ingredient in recipe.Ingredients.Split('\n'))
                        {
                            <li>• @ingredient</li>
                        }
                    </ul>
                </div>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">👨‍🍳 Steps</h5></div>
                <div class="card-body">
                    @foreach (var step in recipe.Steps.Split('\n'))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetRecipeById(RecipeId);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit Recipe - RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

<div class="row">
    <div class="col-md-8">
        <EditForm Model="newRecipe" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
            <DataAnnotationsValidator />

            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" @bind-Value="newRecipe.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                <ValidationMessage For="() => newRecipe.Title" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" @bind-Value="newRecipe.Category" class="form-select">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in RecipeService.GetCategories())
                    {
                        <option value="@cat.Name">@cat.Name</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => newRecipe.Category" />
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients</label>
                <InputTextArea id="ingredients" @bind-Value="newRecipe.Ingredients" class="form-control" rows="6"
                    placeholder="One ingredient per line" />
                <ValidationMessage For="() => newRecipe.Ingredients" />
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps</label>
                <InputTextArea id="steps" @bind-Value="newRecipe.Steps" class="form-control" rows="8"
                    placeholder="Describe each step" />
                <ValidationMessage For="() => newRecipe.Steps" />
            </div>

            <button type="submit" class="btn btn-success">Submit Recipe</button>
        </EditForm>

        @if (showSuccess)
        {
            <div class="alert alert-success mt-3">
                ✅ Recipe submitted successfully! <a href="/recipe/@submittedId">View your recipe</a>
            </div>
        }
    </div>
</div>

@code {
    private Recipe newRecipe = new();
    private bool showSuccess;
    private int submittedId;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(newRecipe);
        submittedId = newRecipe.Id;
        showSuccess = true;
        newRecipe = new();
    }
}

